```class Solution {
    public int hardestWorker(int n, int[][] logs) {
        int maxTime = 0;
        int res = 0;
        for (int i = 0; i < logs.length; i++) {
            if (i == 0) {
                maxTime = logs[i][1];
            } else {
                maxTime = Math.max(maxTime, logs[i][1] - logs[i - 1][1]);
            }
            if (logs[i][1] - logs[i - 1][1] > maxTime) {
                maxTime = logs[i][1] - logs[i - 1][1];
                res = logs[i][0];
            }
        }
        return res;
    }
}```
